export async function chamarChatGPT(perguntaPreparada, isArbiter) {
 let resp = await fetch("http://localhost:5000/testegrok", 
{method: "POST", body: JSON.stringify({pergunta: perguntaPreparada, isArbiter: isArbiter })})
 let rJson = await resp.json()
 return rJson
}
